        cudaMemcpy(d_graph_visited, h_graph_visited, no_of_nodes*sizeof(char), cudaMemcpyHostToDevice);
        cudaMemcpy(d_cost, h_cost, no_of_nodes*sizeof(int), cudaMemcpyHostToDevice);

#ifdef PROFILING
        timer kernel_timer;
        double kernel_time = 0.0;
        kernel_timer.reset();
        kernel_timer.start();
#endif
        do {
            h_over = false;
            cudaMemcpy(d_over, &h_over, sizeof(char), cudaMemcpyHostToDevice);

            int kernel_id = 0;
            BFS_1<<<(no_of_nodes + work_group_size - 1) / work_group_size, work_group_size>>>(
                d_graph_nodes, d_graph_edges, d_graph_mask, d_updating_graph_mask,
                d_graph_visited, d_cost, no_of_nodes);

